22	const PROCESSING_FEE = 5;
23	const FIRST_INSURANCE_SURCHARGE = 0.1;
24	const LOYALTY_DISCOUNT = 0.2;
25	const LOYALTY_THRESHOLD_YEARS = 2;
26	const FOLLOWUP_CONTRACT_DISCOUNT = 0.15;
27	const CURSED_SURCHARGE = 0.5;
28	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
29	const HIGH_ENCHANTMENT_THRESHOLD = 5;
30	
31	const ITEM_BASE_PREMIUM: Record<string, number> = {
32	  sword: 100,
33	  rune: 25,
34	  moonstone: 25,
35	};
36	
37	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
38	const COMPONENT_BLOCK_SIZE = 3;
39	const COMPONENT_BLOCK_PREMIUM = 60;
40	
41	const groupCountsByType = (items: Item[]): Map<string, number> => {
42	  const counts = new Map<string, number>();
43	  for (const item of items) counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
44	  return counts;
45	};
46	
47	const basePremiumForGroup = (type: string, count: number): number => {
48	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
49	  return count * ITEM_BASE_PREMIUM[type];
50	};
51	
52	const sumBasePremium = (counts: Map<string, number>): number => {
53	  let total = 0;
54	  for (const [type, count] of counts) total += basePremiumForGroup(type, count);
55	  return total;
56	};
57	
58	const isHighlyEnchanted = (item: Item): boolean =>
59	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
60	
61	const surchargeRateForItem = (item: Item): number =>
62	  (item.cursed ? CURSED_SURCHARGE : 0) +
63	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE : 0);
64	
65	const surchargeForItem = (item: Item): number =>
66	  ITEM_BASE_PREMIUM[item.type] * surchargeRateForItem(item);
67	
68	const itemSurcharges = (items: Item[]): number =>
69	  items.reduce((total, item) => total + surchargeForItem(item), 0);
70	
71	const calculatePremium = (
72	  items: Item[],
73	  yearsWithMHPCO: number,
74	  isFollowUpContract: boolean,
75	): number => {
76	  const base = sumBasePremium(groupCountsByType(items));
77	  const surcharges = itemSurcharges(items);
78	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE;
79	  const loyaltyDiscount =
80	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT : 0;
81	  const followUpDiscount = isFollowUpContract ? base * FOLLOWUP_CONTRACT_DISCOUNT : 0;
82	  return Math.ceil(
83	    base + surcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE,
84	  );
85	};
